import 'dart:math';

import 'package:flutter_fractals/features/renderer/deep_zoom_precision_policy.dart';

/// Auto-zoom configuration.
class AutoExploreConfig {
  static const double defaultMinZoom = 0.2;
  static const double defaultMaxZoom = 1e12;

  /// Minimum and maximum zoom targets for the auto cycle.
  final double minZoom;
  final double maxZoom;

  /// Peak zoom target starts from: baseZoom * [cycleMaxMultiplier], then gets
  /// clamped by smart precision limits per fractal module.
  final double cycleMaxMultiplier;

  /// Maximum zoom span per leg in log10 decades (e.g. 3.0 => up to 1000x).
  final double maxLegSpanDecades;

  /// Precision headroom under policy threshold to avoid probing unstable edges.
  final double precisionHeadroom;

  /// Duration for each zoom leg (in or out).
  final Duration travelDuration;

  /// Maximum multiplier for duration scaling on very large zoom spans.
  final double maxDurationScale;

  const AutoExploreConfig({
    this.minZoom = defaultMinZoom,
    this.maxZoom = defaultMaxZoom,
    this.cycleMaxMultiplier = 120.0,
    this.maxLegSpanDecades = 3.2,
    this.precisionHeadroom = 0.92,
    this.travelDuration = const Duration(milliseconds: 9000),
    this.maxDurationScale = 4.0,
  });
}

/// Speed bounds used by auto-explore playback.
///
/// Dart's [double.clamp] treats NaN as the upper bound. For playback speed,
/// invalid telemetry or UI state should fall back to neutral 1.0x instead of
/// silently selecting the fastest supported speed.
class AutoExploreSpeed {
  static const double min = 0.5;
  static const double neutral = 1.0;
  static const double max = 3.0;

  const AutoExploreSpeed._();

  static double normalize(double speed) {
    if (speed.isNaN) return neutral;
    return speed.clamp(min, max);
  }
}

/// Relative epsilon used to ignore tiny user zoom corrections.
///
/// Values at or above 1.0 invert the lower comparison bound and make zoom-out
/// corrections undetectable. Keep normalization explicit so correction replay
/// tests can distinguish real deadbands from malformed inputs.
class AutoExploreRelativeEpsilon {
  static const double defaultValue = 1e-4;

  const AutoExploreRelativeEpsilon._();

  static double normalize(double epsilon) {
    if (!epsilon.isFinite || epsilon < 0.0 || epsilon >= 1.0) {
      return defaultValue;
    }
    return epsilon;
  }
}

/// Direction inferred from a user zoom correction.
class AutoExploreCorrectionDecision {
  static const double defaultRelativeEpsilon =
      AutoExploreRelativeEpsilon.defaultValue;

  /// Null means the correction is inside the deadband and should preserve the
  /// current auto-explore direction.
  final bool? zoomingInOverride;

  const AutoExploreCorrectionDecision._(this.zoomingInOverride);

  bool get changedDirection => zoomingInOverride != null;

  bool resolve({required bool currentZoomingIn}) =>
      zoomingInOverride ?? currentZoomingIn;

  factory AutoExploreCorrectionDecision.fromZooms({
    required double currentZoom,
    required double previousZoom,
    double relativeEpsilon = defaultRelativeEpsilon,
  }) {
    if (!_isUsableZoomSample(currentZoom) ||
        !_isUsableZoomSample(previousZoom)) {
      return const AutoExploreCorrectionDecision._(null);
    }

    final epsilon = AutoExploreRelativeEpsilon.normalize(relativeEpsilon);
    if (currentZoom > previousZoom * (1.0 + epsilon)) {
      return const AutoExploreCorrectionDecision._(true);
    }
    if (currentZoom < previousZoom * (1.0 - epsilon)) {
      return const AutoExploreCorrectionDecision._(false);
    }
    return const AutoExploreCorrectionDecision._(null);
  }

  static bool _isUsableZoomSample(double zoom) => zoom.isFinite && zoom > 0.0;
}

/// Precision headroom used to keep auto-explore below renderer fallback edges.
///
/// Values above 1.0 would push candidates past the module precision threshold;
/// non-finite values must not rely on [double.clamp] because NaN clamps to the
/// upper bound and would silently promote targets to max zoom.
class AutoExplorePrecisionHeadroom {
  static const double neutral = 1.0;

  const AutoExplorePrecisionHeadroom._();

  static double normalize(double headroom) {
    if (!headroom.isFinite || headroom <= 0.0) return neutral;
    return headroom.clamp(0.0, neutral);
  }
}

/// Cycle shape used by auto-explore target planning.
///
/// Invalid multipliers or span limits can otherwise turn zoom-out floors into
/// max zooms or collapse peak candidates into NaN/minimum zooms. Keeping the
/// cycle shape explicit makes candidate planning replayable from config alone.
class AutoExploreCycleShape {
  final double cycleMaxMultiplier;
  final double maxLegSpanDecades;

  const AutoExploreCycleShape({
    required this.cycleMaxMultiplier,
    required this.maxLegSpanDecades,
  });

  factory AutoExploreCycleShape.fromConfig(AutoExploreConfig config) {
    return AutoExploreCycleShape(
      cycleMaxMultiplier: _finiteAboveNeutralOrDefault(
        config.cycleMaxMultiplier,
        const AutoExploreConfig().cycleMaxMultiplier,
      ),
      maxLegSpanDecades: _finiteNonNegativeOrDefault(
        config.maxLegSpanDecades,
        const AutoExploreConfig().maxLegSpanDecades,
      ),
    );
  }

  static double _finiteAboveNeutralOrDefault(double value, double fallback) {
    return value.isFinite && value > 1.0 ? value : fallback;
  }

  static double _finiteNonNegativeOrDefault(double value, double fallback) {
    return value.isFinite && value >= 0.0 ? value : fallback;
  }
}

/// Duration scaling used by auto-explore zoom legs.
///
/// Invalid scale factors can otherwise flow into [double.round], where NaN or
/// infinity throws instead of producing a replayable fallback duration.
class AutoExploreDurationScale {
  static const double neutral = 1.0;

  const AutoExploreDurationScale._();

  static double normalize(double scale) {
    if (!scale.isFinite || scale < neutral) return neutral;
    return scale;
  }
}

/// Converts a zoom span into a normalized duration scale.
///
/// A leg reaches the configured maximum duration scale after this many log10
/// decades. Keeping the threshold named makes the cinematic timing assumption
/// replayable instead of burying `1.6` in duration planning.
class AutoExploreZoomSpanScale {
  static const double maxScaleSpanDecades = 1.6;

  const AutoExploreZoomSpanScale._();

  static double normalized(double spanDecades) {
    if (!spanDecades.isFinite || spanDecades <= 0.0) return 0.0;
    return (spanDecades / maxScaleSpanDecades).clamp(0.0, 1.0);
  }
}

/// Converts zoom-span scaling into a positive, finite leg duration.
///
/// This keeps duration planning replayable even when a finite-but-huge config
/// value overflows during multiplication before [double.round].
class AutoExploreLegDuration {
  // Dart Duration stores microseconds in a signed 64-bit field. Millisecond
  // candidates above this can overflow into negative durations after the
  // milliseconds-to-microseconds conversion.
  static const int _maxSafeDurationMilliseconds = 9223372036854;

  const AutoExploreLegDuration._();

  static int milliseconds({
    required Duration baseDuration,
    required double scale,
    required double speed,
  }) {
    final baseMs = baseDuration.inMilliseconds;
    if (baseMs <= 0) return 1;

    final scaledMs = _finitePositiveRoundOrFallback(
      baseMs * scale,
      fallback: baseMs,
    );
    return max(
      1,
      _finitePositiveRoundOrFallback(
        scaledMs / AutoExploreSpeed.normalize(speed),
        fallback: baseMs,
      ),
    );
  }

  static int _finitePositiveRoundOrFallback(
    double value, {
    required int fallback,
  }) {
    if (!value.isFinite ||
        value <= 0.0 ||
        value > _maxSafeDurationMilliseconds) {
      return fallback;
    }
    return value.round();
  }
}

/// Zoom bounds used by auto-explore planning.
///
/// Dart's [double.clamp] treats NaN as the upper bound, which would turn a
/// corrupted/uninitialized zoom reading into an extreme deep-zoom target.
/// Keep sanitization explicit so candidate planning remains replayable.
class AutoExploreZoomBounds {
  final double minZoom;
  final double maxZoom;

  const AutoExploreZoomBounds({
    required this.minZoom,
    required this.maxZoom,
  });

  factory AutoExploreZoomBounds.fromConfig(AutoExploreConfig config) {
    final configuredMin = _positiveFiniteOrDefault(
      config.minZoom,
      AutoExploreConfig.defaultMinZoom,
    );
    final configuredMax = _positiveFiniteOrDefault(
      config.maxZoom,
      AutoExploreConfig.defaultMaxZoom,
    );

    return AutoExploreZoomBounds(
      minZoom: min(configuredMin, configuredMax),
      maxZoom: max(configuredMin, configuredMax),
    );
  }

  static double _positiveFiniteOrDefault(double value, double fallback) {
    return value.isFinite && value > 0.0 ? value : fallback;
  }

  double clamp(double zoom) {
    if (zoom.isNaN) return minZoom;
    return zoom.clamp(minZoom, maxZoom);
  }
}

/// Replayable zoom-span math for positive, finite zoom endpoints.
///
/// Computing the ratio before taking the logarithm can overflow for valid deep
/// zoom bounds (for example `1e308 / 0.2`). Use log-space subtraction so huge
/// but finite legs still scale duration instead of looking like malformed data.
class AutoExploreZoomSpan {
  const AutoExploreZoomSpan._();

  static double decades({
    required double startZoom,
    required double endZoom,
  }) {
    final low = min(startZoom, endZoom);
    final high = max(startZoom, endZoom);
    if (low <= 0.0 || high <= low) return 0.0;

    final span = (log(high) - log(low)) / ln10;
    return span.isFinite && span > 0.0 ? span : 0.0;
  }
}

/// Sanitized zoom leg used for replayable duration/interpolation math.
class AutoExploreZoomLeg {
  final double startZoom;
  final double endZoom;

  const AutoExploreZoomLeg({
    required this.startZoom,
    required this.endZoom,
  });

  factory AutoExploreZoomLeg.fromBounds({
    required AutoExploreZoomBounds bounds,
    required double startZoom,
    required double endZoom,
  }) {
    return AutoExploreZoomLeg(
      startZoom: bounds.clamp(startZoom),
      endZoom: bounds.clamp(endZoom),
    );
  }

  double get spanDecades => AutoExploreZoomSpan.decades(
        startZoom: startZoom,
        endZoom: endZoom,
      );

  double interpolate(double t) {
    return AutoExploreZoomInterpolation.interpolate(
      startZoom: startZoom,
      endZoom: endZoom,
      t: t,
    );
  }
}

/// Numerically stable geometric interpolation for positive zoom legs.
class AutoExploreZoomInterpolation {
  const AutoExploreZoomInterpolation._();

  static double interpolate({
    required double startZoom,
    required double endZoom,
    required double t,
  }) {
    final progress = t.isNaN ? 0.0 : t.clamp(0.0, 1.0);
    if (progress <= 0.0) return startZoom;
    if (progress >= 1.0) return endZoom;

    final interpolated = exp(
      log(startZoom) + (log(endZoom) - log(startZoom)) * progress,
    );
    if (interpolated.isFinite) return interpolated;
    return progress < 0.5 ? startZoom : endZoom;
  }
}

/// Replayable peak candidate data for one auto-explore cycle step.
class AutoExplorePeakZoomCandidates {
  final double baseZoom;
  final double minProgressZoom;
  final double configuredPeakZoom;
  final double spanLimitedPeakZoom;
  final double hardMaxZoom;

  const AutoExplorePeakZoomCandidates({
    required this.baseZoom,
    required this.minProgressZoom,
    required this.configuredPeakZoom,
    required this.spanLimitedPeakZoom,
    required this.hardMaxZoom,
  });

  double get desiredPeakZoom => min(configuredPeakZoom, spanLimitedPeakZoom);

  /// The 1.25x progress nudge is a preference, not permission to violate the
  /// configured per-leg span cap or module precision hard maximum.
  double get cappedMinimumProgressZoom => min(minProgressZoom, desiredPeakZoom);

  double get resolvedPeakZoom => min(
        max(cappedMinimumProgressZoom, min(desiredPeakZoom, hardMaxZoom)),
        hardMaxZoom,
      );
}

/// Replayable target-selection data for one auto-explore cycle step.
class AutoExploreZoomTargetPlan {
  static const double collapseEpsilon = 1e-9;

  final double currentZoom;
  final double baseZoom;
  final double peakZoom;
  final double floorZoom;
  final bool zoomingIn;

  const AutoExploreZoomTargetPlan({
    required this.currentZoom,
    required this.baseZoom,
    required this.peakZoom,
    required this.floorZoom,
    required this.zoomingIn,
  });

  bool get isCollapsed => (peakZoom - floorZoom).abs() < collapseEpsilon;

  double get targetZoom => isCollapsed
      ? baseZoom
      : zoomingIn
          ? peakZoom
          : floorZoom;
}

/// Pure zoom-planning logic for [AutoExploreService].
///
/// Keeping target selection side-effect free makes the precision assumptions
/// replayable in tests without constructing timers or a renderer controller.
class AutoExploreZoomPlanner {
  final AutoExploreConfig config;
  final DeepZoomPrecisionPolicy precisionPolicy;

  const AutoExploreZoomPlanner({
    required this.config,
    this.precisionPolicy = const DeepZoomPrecisionPolicy(),
  });

  AutoExploreZoomBounds get _bounds => AutoExploreZoomBounds.fromConfig(config);
  AutoExploreCycleShape get _cycleShape =>
      AutoExploreCycleShape.fromConfig(config);

  double clampZoom(double zoom) => _bounds.clamp(zoom);

  double hardMaxZoomFor(String moduleId) {
    final headroom = AutoExplorePrecisionHeadroom.normalize(
      config.precisionHeadroom,
    );
    final safeThreshold = precisionPolicy.thresholdFor(moduleId) * headroom;
    return _bounds.clamp(safeThreshold);
  }

  AutoExplorePeakZoomCandidates peakZoomCandidates({
    required double baseZoom,
    required String moduleId,
  }) {
    final base = clampZoom(baseZoom);
    final hardMax = hardMaxZoomFor(moduleId);
    final cycleShape = _cycleShape;
    final maxSpanRatio = pow(10.0, cycleShape.maxLegSpanDecades).toDouble();

    return AutoExplorePeakZoomCandidates(
      baseZoom: base,
      minProgressZoom: clampZoom(base * 1.25),
      configuredPeakZoom: clampZoom(base * cycleShape.cycleMaxMultiplier),
      spanLimitedPeakZoom: clampZoom(base * maxSpanRatio),
      hardMaxZoom: hardMax,
    );
  }

  double computePeakZoom({
    required double baseZoom,
    required String moduleId,
  }) {
    return peakZoomCandidates(
      baseZoom: baseZoom,
      moduleId: moduleId,
    ).resolvedPeakZoom;
  }

  double computeFloorZoom(double baseZoom) {
    final bounds = _bounds;
    final base = bounds.clamp(baseZoom);
    final contextualFloor = base / _cycleShape.cycleMaxMultiplier;
    return bounds.clamp(max(bounds.minZoom, contextualFloor));
  }

  AutoExploreZoomTargetPlan planNextTarget({
    required double currentZoom,
    required double? cycleBaseZoom,
    required bool zoomingIn,
    required String moduleId,
  }) {
    final current = clampZoom(currentZoom);
    final baseZoom = clampZoom(cycleBaseZoom ?? current);
    return AutoExploreZoomTargetPlan(
      currentZoom: current,
      baseZoom: baseZoom,
      peakZoom: computePeakZoom(baseZoom: baseZoom, moduleId: moduleId),
      floorZoom: computeFloorZoom(baseZoom),
      zoomingIn: zoomingIn,
    );
  }

  double nextTargetZoom({
    required double currentZoom,
    required double? cycleBaseZoom,
    required bool zoomingIn,
    required String moduleId,
  }) {
    return planNextTarget(
      currentZoom: currentZoom,
      cycleBaseZoom: cycleBaseZoom,
      zoomingIn: zoomingIn,
      moduleId: moduleId,
    ).targetZoom;
  }

  Duration durationForZoomLeg({
    required double startZoom,
    required double endZoom,
    required double speed,
  }) {
    final leg = AutoExploreZoomLeg.fromBounds(
      bounds: _bounds,
      startZoom: startZoom,
      endZoom: endZoom,
    );
    final effectiveSpeed = _effectiveSpeed(speed);

    final durationScale = AutoExploreDurationScale.normalize(
      config.maxDurationScale,
    );
    final normalized = AutoExploreZoomSpanScale.normalized(leg.spanDecades);
    final scale = 1.0 + normalized * (durationScale - 1.0);

    return Duration(
      milliseconds: AutoExploreLegDuration.milliseconds(
        baseDuration: config.travelDuration,
        scale: scale,
        speed: effectiveSpeed,
      ),
    );
  }

  double _effectiveSpeed(double speed) => AutoExploreSpeed.normalize(speed);

  double interpolateZoom(double start, double end, double t) {
    final leg = AutoExploreZoomLeg.fromBounds(
      bounds: _bounds,
      startZoom: start,
      endZoom: end,
    );
    return leg.interpolate(t);
  }
}

import 'package:flutter_fractals/features/auto_explore/auto_explore_zoom_planner.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('AutoExploreCorrectionDecision', () {
    test('maps visible zoom changes to the next leg direction', () {
      expect(
        AutoExploreCorrectionDecision.fromZooms(
          currentZoom: 10.002,
          previousZoom: 10.0,
        ).resolve(currentZoomingIn: false),
        isTrue,
      );
      expect(
        AutoExploreCorrectionDecision.fromZooms(
          currentZoom: 9.998,
          previousZoom: 10.0,
        ).resolve(currentZoomingIn: true),
        isFalse,
      );
    });

    test('preserves current direction inside the correction deadband', () {
      final decision = AutoExploreCorrectionDecision.fromZooms(
        currentZoom: 10.0005,
        previousZoom: 10.0,
      );

      expect(decision.changedDirection, isFalse);
      expect(decision.resolve(currentZoomingIn: true), isTrue);
      expect(decision.resolve(currentZoomingIn: false), isFalse);
    });

    test('normalizes malformed correction epsilon', () {
      final decision = AutoExploreCorrectionDecision.fromZooms(
        currentZoom: 10.0005,
        previousZoom: 10.0,
        relativeEpsilon: double.nan,
      );

      expect(decision.changedDirection, isFalse);
      expect(AutoExploreRelativeEpsilon.normalize(-0.1), 1e-4);
      expect(AutoExploreRelativeEpsilon.normalize(double.infinity), 1e-4);
    });

    test('normalizes correction epsilon before it hides zoom-out intent', () {
      final decision = AutoExploreCorrectionDecision.fromZooms(
        currentZoom: 5.0,
        previousZoom: 10.0,
        relativeEpsilon: 1.5,
      );

      expect(AutoExploreRelativeEpsilon.normalize(1.5), 1e-4);
      expect(decision.changedDirection, isTrue);
      expect(decision.resolve(currentZoomingIn: true), isFalse);
    });

    test('preserves direction when correction zoom samples are unusable', () {
      for (final sample in [
        (currentZoom: double.nan, previousZoom: 10.0),
        (currentZoom: double.infinity, previousZoom: 10.0),
        (currentZoom: 10.0, previousZoom: double.nan),
        (currentZoom: 10.0, previousZoom: double.infinity),
        (currentZoom: 10.0, previousZoom: 0.0),
      ]) {
        final decision = AutoExploreCorrectionDecision.fromZooms(
          currentZoom: sample.currentZoom,
          previousZoom: sample.previousZoom,
        );

        expect(
          decision.changedDirection,
          isFalse,
          reason:
              'current=${sample.currentZoom}, previous=${sample.previousZoom}',
        );
        expect(decision.resolve(currentZoomingIn: true), isTrue);
        expect(decision.resolve(currentZoomingIn: false), isFalse);
      }
    });
  });

  group('AutoExploreZoomSpanScale', () {
    test('makes the cinematic duration span threshold explicit', () {
      expect(AutoExploreZoomSpanScale.normalized(double.nan), 0.0);
      expect(AutoExploreZoomSpanScale.normalized(-1.0), 0.0);
      expect(AutoExploreZoomSpanScale.normalized(0.8), 0.5);
      expect(AutoExploreZoomSpanScale.normalized(1.6), 1.0);
      expect(AutoExploreZoomSpanScale.normalized(3.2), 1.0);
    });
  });

  group('AutoExploreZoomPlanner', () {
    const planner = AutoExploreZoomPlanner(config: AutoExploreConfig());

    test('keeps peak zoom under module precision headroom', () {
      // Unknown modules use the default 1e7 precision threshold, so headroom is
      // 9.2e6. A base zoom near that edge used to let the 1.25x minimum peak
      // overrun the module-aware hard max.
      const moduleId = 'unknown_orbit_module';
      const baseZoom = 9.0e6;

      final hardMax = planner.hardMaxZoomFor(moduleId);
      final peakZoom = planner.computePeakZoom(
        baseZoom: baseZoom,
        moduleId: moduleId,
      );

      expect(hardMax, 9.2e6);
      expect(peakZoom, hardMax);
      expect(peakZoom, lessThanOrEqualTo(hardMax));
    });

    test('does not promote invalid precision headroom to max zoom', () {
      const planner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(precisionHeadroom: double.nan),
      );

      expect(planner.hardMaxZoomFor('unknown_orbit_module'), 1e7);
      expect(
        planner.computePeakZoom(
          baseZoom: 9.0e6,
          moduleId: 'unknown_orbit_module',
        ),
        lessThanOrEqualTo(1e7),
      );
    });

    test('plans zoom-in and zoom-out targets from the same cycle base', () {
      const baseZoom = 10.0;

      final zoomInPlan = planner.planNextTarget(
        currentZoom: 12.0,
        cycleBaseZoom: baseZoom,
        zoomingIn: true,
        moduleId: 'mandelbrot',
      );
      final zoomOutPlan = planner.planNextTarget(
        currentZoom: 12.0,
        cycleBaseZoom: baseZoom,
        zoomingIn: false,
        moduleId: 'mandelbrot',
      );

      expect(zoomInPlan.currentZoom, 12.0);
      expect(zoomInPlan.baseZoom, baseZoom);
      expect(zoomInPlan.peakZoom, 1200.0);
      expect(zoomInPlan.floorZoom, AutoExploreConfig().minZoom);
      expect(zoomInPlan.targetZoom, 1200.0);
      expect(zoomOutPlan.targetZoom, AutoExploreConfig().minZoom);
      expect(
        planner.nextTargetZoom(
          currentZoom: 12.0,
          cycleBaseZoom: baseZoom,
          zoomingIn: true,
          moduleId: 'mandelbrot',
        ),
        zoomInPlan.targetZoom,
      );
    });

    test('makes collapsed target plans explicit', () {
      const collapsedPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(minZoom: 1.0, maxZoom: 1.0),
      );

      final plan = collapsedPlanner.planNextTarget(
        currentZoom: 42.0,
        cycleBaseZoom: null,
        zoomingIn: true,
        moduleId: 'unknown_orbit_module',
      );

      expect(plan.currentZoom, 1.0);
      expect(plan.baseZoom, 1.0);
      expect(plan.peakZoom, 1.0);
      expect(plan.floorZoom, 1.0);
      expect(plan.isCollapsed, isTrue);
      expect(plan.targetZoom, 1.0);
    });

    test('scales leg duration by zoom span and speed', () {
      const config = AutoExploreConfig(
        travelDuration: Duration(milliseconds: 1000),
        maxDurationScale: 4.0,
      );
      const fastPlanner = AutoExploreZoomPlanner(config: config);

      expect(
        fastPlanner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1.0,
          speed: 2.0,
        ),
        const Duration(milliseconds: 500),
      );
      expect(
        fastPlanner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1e6,
          speed: 2.0,
        ),
        const Duration(milliseconds: 2000),
      );
    });

    test('normalizes invalid speed candidates before duration scaling', () {
      const config = AutoExploreConfig(
        travelDuration: Duration(milliseconds: 1000),
        maxDurationScale: 4.0,
      );
      const planner = AutoExploreZoomPlanner(config: config);

      expect(AutoExploreSpeed.normalize(0.0), 0.5);
      expect(AutoExploreSpeed.normalize(double.nan), 1.0);

      expect(
        planner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1.0,
          speed: 0.0,
        ),
        const Duration(milliseconds: 2000),
      );
      expect(
        planner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1.0,
          speed: double.nan,
        ),
        const Duration(milliseconds: 1000),
      );
    });

    test('does not treat NaN zoom as maximum zoom', () {
      const planner = AutoExploreZoomPlanner(config: AutoExploreConfig());

      expect(planner.clampZoom(double.nan), AutoExploreConfig().minZoom);
      expect(
        planner.nextTargetZoom(
          currentZoom: double.nan,
          cycleBaseZoom: null,
          zoomingIn: true,
          moduleId: 'mandelbrot',
        ),
        24.0,
      );
    });

    test('normalizes malformed zoom bounds before clamping candidates', () {
      const reversedPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(minZoom: 100.0, maxZoom: 1.0),
      );
      const invalidPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(minZoom: double.nan, maxZoom: -1.0),
      );

      expect(reversedPlanner.clampZoom(0.5), 1.0);
      expect(reversedPlanner.clampZoom(200.0), 100.0);
      expect(invalidPlanner.clampZoom(double.nan), 0.2);
      expect(invalidPlanner.clampZoom(double.infinity), 1e12);
    });

    test('uses normalized zoom bounds for precision hard max planning', () {
      const reversedPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(minZoom: 100.0, maxZoom: 1.0),
      );
      const invalidPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(minZoom: double.nan, maxZoom: -1.0),
      );

      expect(reversedPlanner.hardMaxZoomFor('unknown_orbit_module'), 100.0);
      expect(invalidPlanner.hardMaxZoomFor('unknown_orbit_module'), 9.2e6);
      expect(
        reversedPlanner.nextTargetZoom(
          currentZoom: 10.0,
          cycleBaseZoom: null,
          zoomingIn: true,
          moduleId: 'unknown_orbit_module',
        ),
        100.0,
      );
    });

    test('sanitizes invalid zoom endpoints before duration math', () {
      const config = AutoExploreConfig(
        travelDuration: Duration(milliseconds: 1000),
        maxDurationScale: 4.0,
      );
      const planner = AutoExploreZoomPlanner(config: config);

      expect(
        planner.durationForZoomLeg(
          startZoom: double.nan,
          endZoom: 1.0,
          speed: 1.0,
        ),
        const Duration(milliseconds: 2311),
      );
      expect(
        planner.durationForZoomLeg(
          startZoom: double.infinity,
          endZoom: 1.0,
          speed: 1.0,
        ),
        const Duration(milliseconds: 4000),
      );
    });

    test('keeps interpolation finite for huge but valid zoom bounds', () {
      const planner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(maxZoom: 1e308),
      );

      expect(planner.interpolateZoom(0.2, 1e308, 0.0), 0.2);
      expect(planner.interpolateZoom(0.2, 1e308, 1.0), 1e308);
      expect(
        planner.interpolateZoom(0.2, 1e308, 0.5),
        predicate<double>((value) => value.isFinite, 'finite zoom'),
      );
      expect(planner.interpolateZoom(0.2, 1e308, double.nan), 0.2);
    });

    test('scales duration for huge but finite zoom spans', () {
      const planner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          maxZoom: 1e308,
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: 4.0,
        ),
      );

      expect(
        planner.durationForZoomLeg(
          startZoom: 0.2,
          endZoom: 1e308,
          speed: 1.0,
        ),
        const Duration(milliseconds: 4000),
      );
    });

    test('exposes peak target candidates for replayable span decisions', () {
      final candidates = planner.peakZoomCandidates(
        baseZoom: 10.0,
        moduleId: 'mandelbrot',
      );

      expect(candidates.baseZoom, 10.0);
      expect(candidates.minProgressZoom, 12.5);
      expect(candidates.configuredPeakZoom, 1200.0);
      expect(
        candidates.spanLimitedPeakZoom,
        moreOrLessEquals(15848.9319, epsilon: 1e-4),
      );
      expect(candidates.hardMaxZoom, 9.2e11);
      expect(candidates.desiredPeakZoom, 1200.0);
      expect(candidates.resolvedPeakZoom, 1200.0);
    });

    test('does not let minimum peak nudge exceed max leg span', () {
      const zeroSpanPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(maxLegSpanDecades: 0.0),
      );

      final candidates = zeroSpanPlanner.peakZoomCandidates(
        baseZoom: 10.0,
        moduleId: 'mandelbrot',
      );

      expect(candidates.minProgressZoom, 12.5);
      expect(candidates.spanLimitedPeakZoom, 10.0);
      expect(candidates.cappedMinimumProgressZoom, 10.0);
      expect(candidates.resolvedPeakZoom, 10.0);
      expect(
        zeroSpanPlanner.computePeakZoom(
          baseZoom: 10.0,
          moduleId: 'mandelbrot',
        ),
        10.0,
      );
    });

    test('normalizes invalid cycle shape before target planning', () {
      const zeroMultiplierPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(cycleMaxMultiplier: 0.0),
      );
      const nanMultiplierPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(cycleMaxMultiplier: double.nan),
      );
      const infiniteMultiplierPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(cycleMaxMultiplier: double.infinity),
      );
      const nanSpanPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(maxLegSpanDecades: double.nan),
      );

      expect(
        zeroMultiplierPlanner.nextTargetZoom(
          currentZoom: 10.0,
          cycleBaseZoom: 10.0,
          zoomingIn: false,
          moduleId: 'mandelbrot',
        ),
        AutoExploreConfig().minZoom,
      );
      for (final planner in [
        nanMultiplierPlanner,
        infiniteMultiplierPlanner,
        nanSpanPlanner,
      ]) {
        expect(
          planner.computePeakZoom(baseZoom: 10.0, moduleId: 'mandelbrot'),
          1200.0,
        );
      }

      expect(
        AutoExploreCycleShape.fromConfig(
          const AutoExploreConfig(cycleMaxMultiplier: 0.0),
        ).cycleMaxMultiplier,
        AutoExploreConfig().cycleMaxMultiplier,
      );
    });

    test('sanitizes invalid duration scale before rounding milliseconds', () {
      const nanScalePlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: double.nan,
        ),
      );
      const infiniteScalePlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: double.infinity,
        ),
      );
      const belowNeutralScalePlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: 0.0,
        ),
      );
      const overflowingFiniteScalePlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: 1e308,
        ),
      );
      const finiteButDurationOverflowingPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: 1e16,
        ),
      );

      for (final planner in [
        nanScalePlanner,
        infiniteScalePlanner,
        belowNeutralScalePlanner,
        overflowingFiniteScalePlanner,
        finiteButDurationOverflowingPlanner,
      ]) {
        expect(
          planner.durationForZoomLeg(
            startZoom: 1.0,
            endZoom: 1e6,
            speed: 1.0,
          ),
          const Duration(milliseconds: 1000),
        );
      }
    });
  });
}

import 'dart:async';
import 'dart:math' show max;

import 'package:flutter/animation.dart';
import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/features/auto_explore/auto_explore_zoom_planner.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';

export 'auto_explore_zoom_planner.dart' show AutoExploreConfig;

/// Auto navigation mode that performs zoom-only cinematic movement.
///
/// Behavior:
/// - Slowly zooms in from the current zoom to a smart module-aware peak.
/// - Then zooms back out to a smart floor.
/// - Repeats continuously.
///
/// Pan is never modified by this service, so the user can pan freely.
class AutoExploreService extends ChangeNotifier {
  static const Cubic _cinematicCurve = Cubic(0.22, 0.0, 0.15, 1.0);

  final FractalController controller;
  final AutoExploreConfig config;
  late final AutoExploreZoomPlanner _zoomPlanner = AutoExploreZoomPlanner(
    config: config,
  );

  bool _isExploring = false;
  bool _isPaused = false;
  bool _pausedByUserCorrection = false;
  bool _isUserInteracting = false;
  double _speed = 1.0;

  Timer? _timer;
  Timer? _anim;

  double? _cycleBaseZoom;
  double? _lastCorrectionZoom;
  double? _interactionStartZoom;
  bool _zoomingIn = true;

  AutoExploreService({
    required this.controller,
    this.config = const AutoExploreConfig(),
  });

  bool get isExploring => _isExploring;
  bool get isPaused => _isPaused;

  /// True while user interaction temporarily takes control.
  bool get pausedByUserCorrection => _pausedByUserCorrection;

  double get speed => _speed;
  set speed(double v) {
    _speed = AutoExploreSpeed.normalize(v);
    notifyListeners();
  }

  void start() {
    if (_isExploring && !_isPaused) return;

    _isExploring = true;
    _isPaused = false;
    _pausedByUserCorrection = false;
    _isUserInteracting = false;
    _interactionStartZoom = null;
    _cycleBaseZoom = _clampZoom(controller.view.zoom);
    _lastCorrectionZoom = _cycleBaseZoom;
    _zoomingIn = true;

    _scheduleNext();
    notifyListeners();
  }

  void pause() {
    if (!_isExploring) return;

    _isPaused = true;
    _pausedByUserCorrection = false;
    _isUserInteracting = false;
    _interactionStartZoom = null;
    _timer?.cancel();
    _anim?.cancel();
    notifyListeners();
  }

  void resume() {
    if (!_isExploring) {
      start();
      return;
    }

    _isPaused = false;
    _pausedByUserCorrection = false;
    _isUserInteracting = false;
    _interactionStartZoom = null;
    _scheduleNext();
    notifyListeners();
  }

  /// Called when user starts a continuous gesture (drag/pinch).
  ///
  /// Auto movement is temporarily suspended so manual pan/zoom is never fought.
  void onUserInteractionStart() {
    if (!_isExploring || _isPaused) return;
    if (_isUserInteracting) return;

    _isUserInteracting = true;
    _pausedByUserCorrection = true;
    _interactionStartZoom = _clampZoom(controller.view.zoom);

    _timer?.cancel();
    _anim?.cancel();
    notifyListeners();
  }

  /// Called when user ends a continuous gesture.
  ///
  /// The user-selected zoom becomes the new baseline and auto mode continues.
  void onUserInteractionEnd() {
    if (!_isExploring) return;

    final referenceZoom = _interactionStartZoom;
    _isUserInteracting = false;
    _interactionStartZoom = null;

    _adoptUserViewAndContinue(referenceZoom: referenceZoom);
  }

  /// Called for one-shot user corrections (mouse wheel, keyboard, etc).
  void onUserCorrection() {
    if (!_isExploring || _isPaused) return;
    _adoptUserViewAndContinue();
  }

  void _adoptUserViewAndContinue({double? referenceZoom}) {
    if (!_isExploring) return;

    final currentZoom = _clampZoom(controller.view.zoom);
    final previousZoom =
        _clampZoom(referenceZoom ?? _lastCorrectionZoom ?? currentZoom);

    final correctionDecision = AutoExploreCorrectionDecision.fromZooms(
      currentZoom: currentZoom,
      previousZoom: previousZoom,
    );
    _zoomingIn = correctionDecision.resolve(currentZoomingIn: _zoomingIn);

    _cycleBaseZoom = currentZoom;
    _lastCorrectionZoom = currentZoom;
    _pausedByUserCorrection = false;

    // Restart leg planning from the user-selected zoom immediately.
    _timer?.cancel();
    _anim?.cancel();
    if (!_isPaused && !_isUserInteracting) {
      _scheduleNext();
    }

    notifyListeners();
  }

  void toggle() {
    if (!_isExploring) return start();
    if (_isPaused) return resume();
    return pause();
  }

  void stop() {
    _isExploring = false;
    _isPaused = false;
    _pausedByUserCorrection = false;
    _isUserInteracting = false;
    _interactionStartZoom = null;
    _timer?.cancel();
    _anim?.cancel();
    _cycleBaseZoom = null;
    _lastCorrectionZoom = null;
    _zoomingIn = true;
    notifyListeners();
  }

  double _clampZoom(double z) => _zoomPlanner.clampZoom(z);

  double _nextTargetZoom() {
    final current = _clampZoom(controller.view.zoom);
    _cycleBaseZoom ??= current;

    // Direction is flipped only after a leg actually reaches its target.
    // This prevents user pan interruptions from resuming in the opposite
    // direction (the reported "reverse" behavior).
    return _zoomPlanner.nextTargetZoom(
      currentZoom: current,
      cycleBaseZoom: _cycleBaseZoom,
      zoomingIn: _zoomingIn,
      moduleId: controller.module.id,
    );
  }

  void _scheduleNext() {
    _timer?.cancel();
    if (!_isExploring || _isPaused || _isUserInteracting) return;

    // Continuous mode: no dwell/pause between zoom-in and zoom-out legs.
    _timer = Timer(Duration.zero, () async {
      if (!_isExploring || _isPaused || _isUserInteracting) return;

      final targetZoom = _nextTargetZoom();
      final reachedTarget = await _animateZoomTo(targetZoom);

      if (!_isExploring || _isPaused || _isUserInteracting) return;
      if (reachedTarget) {
        _zoomingIn = !_zoomingIn;
      }
      _scheduleNext();
    });
  }

  Duration _durationForZoomLeg(double startZoom, double endZoom) {
    return _zoomPlanner.durationForZoomLeg(
      startZoom: startZoom,
      endZoom: endZoom,
      speed: _speed,
    );
  }

  Future<bool> _animateZoomTo(double targetZoom) async {
    _anim?.cancel();

    final startZoom = _clampZoom(controller.view.zoom);
    final endZoom = _clampZoom(targetZoom);

    final duration = _durationForZoomLeg(startZoom, endZoom);
    const frame = Duration(milliseconds: 16);
    final total =
        max(1, (duration.inMilliseconds / frame.inMilliseconds).round());
    var step = 0;

    final completer = Completer<bool>();
    _anim = Timer.periodic(frame, (timer) {
      if (!_isExploring || _isPaused || _isUserInteracting) {
        timer.cancel();
        _anim = null;
        if (!completer.isCompleted) completer.complete(false);
        return;
      }

      step++;
      final raw = (step / total).clamp(0.0, 1.0);
      final eased = _cinematicCurve.transform(raw);

      controller.updateZoom(_interpolateZoom(startZoom, endZoom, eased));
      _lastCorrectionZoom = _clampZoom(controller.view.zoom);

      if (raw >= 1.0) {
        timer.cancel();
        _anim = null;
        if (!completer.isCompleted) completer.complete(true);
      }
    });

    return completer.future;
  }

  double _interpolateZoom(double start, double end, double t) {
    return _zoomPlanner.interpolateZoom(start, end, t);
  }

  @override
  void dispose() {
    stop();
    super.dispose();
  }
}

